import React, { useState } from 'react';

export default function AIChatPanel({ isOpen, onClose }) {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState([{ role: 'assistant', content: 'Halo! Saya RouteAI.' }]);

  const send = () => {
    if (!input.trim()) return;
    setMessages(prev => [...prev, { role: 'user', content: input }]);
    setInput('');
    setTimeout(() => {
      setMessages(prev => [...prev, { role: 'assistant', content: 'Maaf, AI sedang offline. Ini pesan demo.' }]);
    }, 500);
  };

  if (!isOpen) return null;

  return (
    <div style={{ position: 'fixed', bottom: 0, left: 0, right: 0, background: '#1e1e2f', padding: 16, zIndex: 1000, borderTop: '1px solid #333', maxHeight: '70vh', overflowY: 'auto', display: 'flex', flexDirection: 'column' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
        <h3>AI Chat (Test)</h3>
        <button onClick={onClose} style={{ background: 'red', color: 'white', border: 'none', padding: '4px 8px' }}>Tutup</button>
      </div>
      <div style={{ flex: 1, marginBottom: 12, maxHeight: '50vh', overflowY: 'auto' }}>
        {messages.map((m, i) => (
          <div key={i} style={{ textAlign: m.role === 'user' ? 'right' : 'left', margin: '4px 0' }}>
            <span style={{ background: m.role === 'user' ? '#6B5CE7' : '#333', padding: '6px 10px', borderRadius: 12, display: 'inline-block' }}>
              {m.content}
            </span>
          </div>
        ))}
      </div>
      <div style={{ display: 'flex', gap: 8 }}>
        <input
          style={{ flex: 1, padding: 8, borderRadius: 8, border: '1px solid #555', background: '#2a2a3a', color: 'white' }}
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && send()}
          placeholder="Ketik pesan..."
          autoFocus
        />
        <button onClick={send} style={{ padding: '8px 16px', background: '#6B5CE7', border: 'none', borderRadius: 8, color: 'white' }}>Kirim</button>
      </div>
    </div>
  );
}
